def _finalize_figure(self, p: Plot) -> None:

    for sub in self._subplots:
        ax = sub["ax"]
        for axis in "xy":
            axis_key = sub[axis]

            # ----
            # Nominal scale handling
            # ----
            scale = self._scales.get(axis_key)
            if isinstance(scale, Nominal):
                # 1. Set limits to +/- 0.5 from first/last tick
                # (but only if the user hasn't specified explicit limits)
                if axis_key not in p._limits:
                    n_ticks = len(ax.get_xticks() if axis == "x" else ax.get_yticks())
                    if n_ticks > 0:
                        if axis == "x":
                            ax.set_xlim(-.5, n_ticks - .5, auto=None)
                        else:
                            ax.set_ylim(n_ticks - .5, -.5, auto=None)

                # 2. Disable grid
                getattr(ax, f"{axis}axis").grid(False)

            # Axis limits
            if axis_key in p._limits:
                convert_units = getattr(ax, f"{axis}axis").convert_units
                a, b = p._limits[axis_key]
                lo = a if a is None else convert_units(a)
                hi = b if b is None else convert_units(b)
                if isinstance(a, str):
                    lo = cast(float, lo) - 0.5
                if isinstance(b, str):
                    hi = cast(float, hi) + 0.5
                ax.set(**{f"{axis}lim": (lo, hi)})

        for var, col in data_vars.items():
            assert_array_equal(mark.passed_data[i][var], split_data[col])

